const educationBySlug: Record<string, EducationProfile> = {};
for (const profile of educationProfiles) {
  educationBySlug[profile.citySlug] = profile;
}
const universitiesByCity: Record<string, UniversityProfile[]> = {};
for (const university of universities) {
  (universitiesByCity[university.citySlug] ??= []).push(university);
}

const VALID_EDUCATION_CATEGORIES: ReadonlySet<string> = new Set([
  "global_academic_hub", "major_university_city", "research_center",
  "student_city", "regional_education_center", "mixed",
]);
const VALID_UNIVERSITY_TYPES: ReadonlySet<string> = new Set([
  "public", "private", "research", "technical", "medical", "business",
]);

/** Build-time integrity guard — throws (failing `next build`) on any invalid record. */
function assertEducationIntegrity(
  education: readonly EducationProfile[],
  unis: readonly UniversityProfile[],
): void {
  const errors: string[] = [];
  const inRange = (n: number) => typeof n === "number" && Number.isFinite(n) && n >= 0 && n <= 100;
  const eduSeen = new Set<string>();
  for (const e of education) {
    if (!e.citySlug) errors.push(`missing citySlug`);
    if (eduSeen.has(e.citySlug)) errors.push(`duplicate education citySlug: ${e.citySlug}`);
    eduSeen.add(e.citySlug);
    const scores = [
      e.educationScore, e.higherEducationScore, e.researchScore,
      e.internationalStudentScore, e.studentFriendlinessScore,
      e.universityDensityScore, e.academicReputationScore,
    ];
    if (scores.some((n) => !inRange(n))) errors.push(`${e.citySlug}: education score out of range`);
    if (!VALID_EDUCATION_CATEGORIES.has(e.educationCategory))
      errors.push(`${e.citySlug}: invalid educationCategory ${e.educationCategory}`);
    const summaries = [
      e.educationSummary, e.studentExperienceSummary, e.researchSummary, e.internationalSummary,
    ];
    if (summaries.some((t) => typeof t !== "string" || t.length === 0))
      errors.push(`${e.citySlug}: missing summary`);
  }
  const idSeen = new Set<string>();
  const cityUniCount = new Map<string, number>();
  for (const u of unis) {
    if (idSeen.has(u.id)) errors.push(`duplicate university id: ${u.id}`);
    idSeen.add(u.id);
    if (!eduSeen.has(u.citySlug)) errors.push(`${u.id}: university references unknown city ${u.citySlug}`);
    if (!VALID_UNIVERSITY_TYPES.has(u.type)) errors.push(`${u.id}: invalid type ${u.type}`);
    if (!["small", "medium", "large"].includes(u.studentPopulationCategory))
      errors.push(`${u.id}: invalid studentPopulationCategory`);
    if (u.focusAreas.length < 2 || u.focusAreas.length > 6)
      errors.push(`${u.id}: focusAreas must be 2-6`);
    if (!inRange(u.internationalFocusScore) || !inRange(u.researchIntensityScore))
      errors.push(`${u.id}: university score out of range`);
    if (u.foundedYear !== undefined && (u.foundedYear < 1000 || u.foundedYear > 2025))
      errors.push(`${u.id}: implausible foundedYear ${u.foundedYear}`);
    cityUniCount.set(u.citySlug, (cityUniCount.get(u.citySlug) ?? 0) + 1);
  }
  for (const slug of eduSeen) {
    const n = cityUniCount.get(slug) ?? 0;
    if (n < 3 || n > 15) errors.push(`${slug}: ${n} universities (must be 3-15)`);
  }
  if (errors.length > 0) {
    throw new Error(`education integrity failure:\n${errors.join("\n")}`);
  }
}

assertEducationIntegrity(educationProfiles, universities);

export function getEducation(citySlug: string): EducationProfile | undefined {
  return educationBySlug[citySlug];
}

export function hasEducation(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(educationBySlug, citySlug);
}

export function getAllEducationProfiles(): readonly EducationProfile[] {
  return educationProfiles;
}

export function getUniversitiesForCity(citySlug: string): readonly UniversityProfile[] {
  return universitiesByCity[citySlug] ?? [];
}

export function getAllUniversities(): readonly UniversityProfile[] {
  return universities;
}
